final_sparql:
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX fq: <https://www.purl.org/futuram/query#>
PREFIX futuram: <https://www.purl.org/futuram#>
SELECT ?c ?label (?frac * ?m AS ?kg) (?relUnc * ?frac * ?m AS ?kgUnc) WHERE {
  futuram:V0401010102_Y2020 fq:itemMass ?m ;
     fq:contains [ fq:constituent ?c ;
                   fq:amount ?frac ;
                   fq:relativeUncertainty ?relUnc ] .
  ?c rdfs:subClassOf* futuram:AlAndAlAlloys .
  OPTIONAL { ?c rdfs:label ?label }
}
ORDER BY DESC(?kg)

